CREATE TYPE "RecordStatus" AS ENUM ('ACTIVE','INACTIVE','ARCHIVED');
CREATE TYPE "HouseholdRole" AS ENUM ('HEAD','SPOUSE','CHILD','DEPENDENT','OTHER');
CREATE TYPE "RelationshipType" AS ENUM ('PARENT','CHILD','SPOUSE','SIBLING','GUARDIAN','OTHER');
CREATE TYPE "AuditOutcome" AS ENUM ('SUCCESS','DENIED','FAILURE');
CREATE TABLE "Tenant" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"status" "RecordStatus" NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "User" ("id" TEXT PRIMARY KEY,"tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"),"email" TEXT NOT NULL,"passwordHash" TEXT NOT NULL,"displayName" TEXT NOT NULL,"status" "RecordStatus" NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "User_tenantId_email_key" ON "User"("tenantId","email");
CREATE TABLE "Role" ("id" TEXT PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL);
CREATE TABLE "Permission" ("id" TEXT PRIMARY KEY,"scope" TEXT NOT NULL UNIQUE,"description" TEXT NOT NULL);
CREATE TABLE "UserRole" ("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"roleId" TEXT NOT NULL REFERENCES "Role"("id") ON DELETE CASCADE,PRIMARY KEY("userId","roleId"));
CREATE TABLE "RolePermission" ("roleId" TEXT NOT NULL REFERENCES "Role"("id") ON DELETE CASCADE,"permissionId" TEXT NOT NULL REFERENCES "Permission"("id") ON DELETE CASCADE,PRIMARY KEY("roleId","permissionId"));
CREATE TABLE "Person" ("id" TEXT PRIMARY KEY,"tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"),"status" "RecordStatus" NOT NULL DEFAULT 'ACTIVE',"givenName" TEXT NOT NULL,"familyName" TEXT NOT NULL,"preferredName" TEXT,"birthDate" TIMESTAMP(3),"provenance" TEXT NOT NULL DEFAULT 'manual',"duplicateSearchRef" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"version" INTEGER NOT NULL DEFAULT 1);
CREATE TABLE "ContactMethod" ("id" TEXT PRIMARY KEY,"personId" TEXT NOT NULL REFERENCES "Person"("id") ON DELETE CASCADE,"type" TEXT NOT NULL,"value" TEXT NOT NULL,"isPrimary" BOOLEAN NOT NULL DEFAULT false,"consented" BOOLEAN NOT NULL DEFAULT false);
CREATE TABLE "Address" ("id" TEXT PRIMARY KEY,"tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"),"label" TEXT NOT NULL,"line1" TEXT NOT NULL,"sector" TEXT,"municipality" TEXT NOT NULL,"province" TEXT NOT NULL,"countryCode" TEXT NOT NULL DEFAULT 'DO',"latitude" DECIMAL(9,6),"longitude" DECIMAL(9,6),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "PersonAddress" ("personId" TEXT NOT NULL REFERENCES "Person"("id") ON DELETE CASCADE,"addressId" TEXT NOT NULL REFERENCES "Address"("id") ON DELETE CASCADE,"validFrom" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"validTo" TIMESTAMP(3),PRIMARY KEY("personId","addressId","validFrom"));
CREATE TABLE "Household" ("id" TEXT PRIMARY KEY,"tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"),"addressId" TEXT REFERENCES "Address"("id"),"name" TEXT NOT NULL,"status" "RecordStatus" NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"version" INTEGER NOT NULL DEFAULT 1);
CREATE TABLE "HouseholdMembership" ("id" TEXT PRIMARY KEY,"householdId" TEXT NOT NULL REFERENCES "Household"("id") ON DELETE CASCADE,"personId" TEXT NOT NULL REFERENCES "Person"("id") ON DELETE CASCADE,"role" "HouseholdRole" NOT NULL,"startDate" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"endDate" TIMESTAMP(3));
CREATE TABLE "Relationship" ("id" TEXT PRIMARY KEY,"tenantId" TEXT NOT NULL,"fromPersonId" TEXT NOT NULL REFERENCES "Person"("id") ON DELETE CASCADE,"toPersonId" TEXT NOT NULL REFERENCES "Person"("id") ON DELETE CASCADE,"type" "RelationshipType" NOT NULL,"startDate" TIMESTAMP(3),"endDate" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "Relationship_tenantId_fromPersonId_toPersonId_type_key" ON "Relationship"("tenantId","fromPersonId","toPersonId","type");
CREATE TABLE "AuditEvent" ("id" TEXT PRIMARY KEY,"tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"),"actorId" TEXT,"action" TEXT NOT NULL,"entityType" TEXT NOT NULL,"entityId" TEXT,"occurredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"correlationId" TEXT NOT NULL,"sourceIp" TEXT,"userAgent" TEXT,"reason" TEXT,"safeSummary" JSONB,"outcome" "AuditOutcome" NOT NULL);
CREATE INDEX "AuditEvent_tenantId_occurredAt_idx" ON "AuditEvent"("tenantId","occurredAt");
CREATE FUNCTION deny_audit_mutation() RETURNS trigger AS $$ BEGIN RAISE EXCEPTION 'Audit events are append-only'; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER "AuditEvent_no_update" BEFORE UPDATE ON "AuditEvent" FOR EACH ROW EXECUTE FUNCTION deny_audit_mutation();
CREATE TRIGGER "AuditEvent_no_delete" BEFORE DELETE ON "AuditEvent" FOR EACH ROW EXECUTE FUNCTION deny_audit_mutation();
